previewCss:
.darma-loader-darma-research-terminal-cursor-wave { --speed: var(--loader-speed, 1s); --accent: var(--loader-color, #22c55e); --accent-2: var(--loader-secondary-color, #38bdf8); display: inline-flex; align-items: center; gap: 8px; padding: 12px 14px; border-radius: 12px; background: #020617; color: var(--accent); font: 700 14px/1 ui-monospace, SFMono-Regular, Menlo, monospace; box-shadow: inset 0 0 0 1px #ffffff18, 0 12px 30px #02061755; }
.darma-loader-darma-research-terminal-cursor-wave__prompt::before { content: "$ "; color: var(--accent-2); }
.darma-loader-darma-research-terminal-cursor-wave__dots { display: inline-flex; gap: 4px; }
.darma-loader-darma-research-terminal-cursor-wave__dots i { width: 5px; height: 5px; border-radius: 50%; background: currentColor; animation: darma-loader-darma-research-darma-loader-darma-research-terminal-cursor-wave-terminal-cursor-wave-terminal-dot calc(var(--speed) * 1) ease-in-out infinite; }
.darma-loader-darma-research-terminal-cursor-wave__dots i:nth-child(2) { animation-delay: .12s; } .darma-loader-darma-research-terminal-cursor-wave__dots i:nth-child(3) { animation-delay: .24s; }
.darma-loader-darma-research-terminal-cursor-wave__cursor { width: 9px; height: 18px; background: var(--accent-2); animation: darma-loader-darma-research-terminal-cursor-wave-terminal-cursor calc(var(--speed) * .8) steps(2,end) infinite; }
@keyframes darma-loader-darma-research-terminal-cursor-wave-terminal-dot { 50% { transform: translateY(-6px); color: var(--accent-2); } }
@keyframes darma-loader-darma-research-terminal-cursor-wave-terminal-cursor { 50% { opacity: 0; } }

